// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

import "./KaboomVault.sol";

/// @title KaboomGame - On-chain 4×4 Mines game with provably fair commit-reveal
/// @notice Core game logic: start game, reveal tiles, cash out. Emits events for reactive handlers.
contract KaboomGame {
    // ═══ CONSTANTS ═══
    uint8 public constant GRID_SIZE = 16; // 4×4
    uint256 public constant HOUSE_EDGE_BPS = 200; // 2% = 200 basis points
    uint256 public constant WAD = 1e18; // Fixed-point precision

    // ═══ STATE ═══
    KaboomVault public vault;
    address public owner;
    uint256 public gameCounter;

    enum GameStatus { None, Active, Won, Lost }

    struct Game {
        address player;
        uint256 betAmount;
        uint8 mineCount;
        uint16 mineLayout;       // bitmap: bit i = 1 means mine at tile i
        bytes32 salt;            // random salt for commitment
        bytes32 commitment;      // keccak256(abi.encodePacked(mineLayout, salt))
        uint16 revealedTiles;    // bitmap: bit i = 1 means tile i is revealed
        uint8 safeTilesRevealed; // count of safe tiles revealed
        uint256 multiplier;      // current multiplier in WAD (1e18 = 1.0x)
        GameStatus status;
        address referrer;
        uint256 timestamp;
    }

    mapping(uint256 => Game) public games;

    // ═══ EVENTS (consumed by reactive handlers) ═══
    event GameStarted(uint256 indexed gameId, address indexed player, uint256 betAmount, uint8 mineCount, bytes32 commitment);
    event BetPlaced(uint256 indexed gameId, address indexed player, uint256 amount, address referrer);
    event TileRevealed(uint256 indexed gameId, uint8 tileIndex, bool safe, uint256 newMultiplier);
    event GameWon(uint256 indexed gameId, address indexed player, uint256 payout, uint256 multiplier);
    event GameLost(uint256 indexed gameId, address indexed player, uint256 betAmount);
    event GameSettled(uint256 indexed gameId, address indexed player, bool won, uint256 amount, uint256 multiplier);

    // ═══ MODIFIERS ═══
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    // ═══ CONSTRUCTOR ═══
    constructor(address _vault) {
        vault = KaboomVault(payable(_vault));
        owner = msg.sender;
    }

    // ═══ GAME FLOW ═══

    /// @notice Start a new game. Bet is sent as msg.value.
    /// @param mineCount Number of mines (1-12)
    /// @param referrer Optional referrer address (address(0) if none)
    function startGame(uint8 mineCount, address referrer) external payable returns (uint256 gameId) {
        require(msg.value > 0, "Must bet something");
        require(mineCount >= 1 && mineCount <= 12, "Mines: 1-12");
        require(msg.value <= vault.getMaxBet(), "Exceeds max bet");

        gameId = ++gameCounter;

        // Generate pseudorandom mine layout
        bytes32 entropy = keccak256(abi.encodePacked(
            block.prevrandao, block.timestamp, msg.sender, gameId, blockhash(block.number - 1)
        ));
        uint16 mineLayout = _generateMineLayout(entropy, mineCount);
        bytes32 salt = keccak256(abi.encodePacked(entropy, "KABOOM_SALT"));
        bytes32 commitment = keccak256(abi.encodePacked(mineLayout, salt));

        games[gameId] = Game({
            player: msg.sender,
            betAmount: msg.value,
            mineCount: mineCount,
            mineLayout: mineLayout,
            salt: salt,
            commitment: commitment,
            revealedTiles: 0,
            safeTilesRevealed: 0,
            multiplier: WAD, // 1.0x
            status: GameStatus.Active,
            referrer: referrer,
            timestamp: block.timestamp
        });

        // Send bet to vault
        vault.receiveBet{value: msg.value}();

        emit GameStarted(gameId, msg.sender, msg.value, mineCount, commitment);
        emit BetPlaced(gameId, msg.sender, msg.value, referrer);
    }

    /// @notice Reveal a tile on the grid
    /// @param gameId The game ID
    /// @param tileIndex Tile position (0-15)
    function revealTile(uint256 gameId, uint8 tileIndex) external {
        Game storage game = games[gameId];
        require(game.status == GameStatus.Active, "Game not active");
        require(msg.sender == game.player, "Not your game");
        require(tileIndex < GRID_SIZE, "Invalid tile");
        require((game.revealedTiles & (1 << tileIndex)) == 0, "Already revealed");

        // Mark tile as revealed
        game.revealedTiles |= uint16(1 << tileIndex);

        bool isMine = (game.mineLayout & (1 << tileIndex)) != 0;

        if (isMine) {
            // BOOM — player loses
            game.status = GameStatus.Lost;
            emit TileRevealed(gameId, tileIndex, false, 0);
            emit GameLost(gameId, game.player, game.betAmount);
            emit GameSettled(gameId, game.player, false, game.betAmount, 0);
        } else {
            // SAFE — increase multiplier
            game.safeTilesRevealed++;
            game.multiplier = _calculateMultiplier(game.safeTilesRevealed, game.mineCount);
            emit TileRevealed(gameId, tileIndex, true, game.multiplier);

            // Auto-cashout if all safe tiles revealed
            uint8 safeTilesTotal = GRID_SIZE - game.mineCount;
            if (game.safeTilesRevealed >= safeTilesTotal) {
                _cashOut(gameId);
            }
        }
    }

    /// @notice Cash out current winnings
    /// @param gameId The game ID
    function cashOut(uint256 gameId) external {
        Game storage game = games[gameId];
        require(game.status == GameStatus.Active, "Game not active");
        require(msg.sender == game.player, "Not your game");
        require(game.safeTilesRevealed > 0, "Reveal at least 1 tile");
        _cashOut(gameId);
    }

    function _cashOut(uint256 gameId) internal {
        Game storage game = games[gameId];
        game.status = GameStatus.Won;

        uint256 payout = (game.betAmount * game.multiplier) / WAD;
        uint256 maxPay = vault.getMaxPayout();
        if (payout > maxPay) payout = maxPay;

        vault.payout(game.player, payout);

        emit GameWon(gameId, game.player, payout, game.multiplier);
        emit GameSettled(gameId, game.player, true, payout, game.multiplier);
    }

    // ═══ VERIFICATION ═══

    /// @notice Verify a game was fair — anyone can call
    function verifyGame(uint256 gameId) external view returns (
        bool verified,
        bytes32 commitment,
        uint16 mineLayout,
        bytes32 salt
    ) {
        Game storage game = games[gameId];
        require(game.status != GameStatus.Active && game.status != GameStatus.None, "Game not settled");

        commitment = game.commitment;
        mineLayout = game.mineLayout;
        salt = game.salt;
        verified = keccak256(abi.encodePacked(mineLayout, salt)) == commitment;
    }

    /// @notice Get full game state
    function getGame(uint256 gameId) external view returns (
        address player,
        uint256 betAmount,
        uint8 mineCount,
        bytes32 commitment,
        uint16 revealedTiles,
        uint8 safeTilesRevealed,
        uint256 multiplier,
        GameStatus status
    ) {
        Game storage g = games[gameId];
        return (g.player, g.betAmount, g.mineCount, g.commitment, g.revealedTiles, g.safeTilesRevealed, g.multiplier, g.status);
    }

    // ═══ INTERNALS ═══

    /// @dev Generate a mine layout bitmap from entropy
    function _generateMineLayout(bytes32 entropy, uint8 mineCount) internal pure returns (uint16 layout) {
        uint8 placed = 0;
        uint256 nonce = 0;
        while (placed < mineCount) {
            uint8 pos = uint8(uint256(keccak256(abi.encodePacked(entropy, nonce))) % GRID_SIZE);
            if ((layout & (1 << pos)) == 0) {
                layout |= uint16(1 << pos);
                placed++;
            }
            nonce++;
        }
    }

    /// @dev Calculate multiplier for n safe tiles revealed with m mines
    /// Formula: product of (GRID_SIZE - i) / (GRID_SIZE - mineCount - i) for i=0..n-1, minus house edge
    /// Returns WAD-scaled (1e18 = 1.0x)
    function _calculateMultiplier(uint8 safeTiles, uint8 mineCount) internal pure returns (uint256) {
        uint256 mult = WAD;
        for (uint8 i = 0; i < safeTiles; i++) {
            uint256 numerator = uint256(GRID_SIZE - i);
            uint256 denominator = uint256(GRID_SIZE - mineCount - i);
            if (denominator == 0) break;
            mult = (mult * numerator) / denominator;
        }
        // Apply house edge: multiply by (1 - 0.02) = 0.98
        mult = (mult * (10000 - HOUSE_EDGE_BPS)) / 10000;
        return mult;
    }
}

contracts/KaboomVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

/// @title KaboomVault - Treasury for the Kaboom! Mines game
/// @notice Holds house bankroll, enforces dynamic bet/payout limits
contract KaboomVault {
    // ═══ STATE ═══
    address public owner;
    address public gameContract;
    address public riskGuardian;

    uint256 public maxBetPercent = 100; // basis points: 100 = 1%
    uint256 public maxPayoutPercent = 1000; // basis points: 1000 = 10%
    uint256 public peakBalance;

    // ═══ EVENTS ═══
    event VaultFunded(address indexed funder, uint256 amount, uint256 newBalance);
    event PayoutSent(address indexed player, uint256 amount, uint256 newBalance);
    event VaultBalanceChanged(uint256 newBalance, uint256 peakBalance);
    event MaxBetPercentChanged(uint256 oldPercent, uint256 newPercent);
    event EmergencyWithdraw(address indexed to, uint256 amount);

    // ═══ MODIFIERS ═══
    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyGame() {
        require(msg.sender == gameContract, "Only game contract");
        _;
    }

    modifier onlyRiskGuardian() {
        require(msg.sender == riskGuardian, "Only risk guardian");
        _;
    }

    // ═══ CONSTRUCTOR ═══
    constructor() {
        owner = msg.sender;
    }

    // ═══ CONFIGURATION ═══
    function setGameContract(address _game) external onlyOwner {
        gameContract = _game;
    }

    function setRiskGuardian(address _guardian) external onlyOwner {
        riskGuardian = _guardian;
    }

    // ═══ VAULT OPERATIONS ═══

    /// @notice Fund the vault (anyone can deposit)
    function deposit() external payable {
        require(msg.value > 0, "Must send STT");
        if (address(this).balance > peakBalance) {
            peakBalance = address(this).balance;
        }
        emit VaultFunded(msg.sender, msg.value, address(this).balance);
        emit VaultBalanceChanged(address(this).balance, peakBalance);
    }

    /// @notice Pay out winnings to a player (only callable by game contract)
    function payout(address player, uint256 amount) external onlyGame {
        require(amount <= address(this).balance, "Insufficient vault balance");
        require(amount <= getMaxPayout(), "Exceeds max payout");

        (bool sent, ) = payable(player).call{value: amount}("");
        require(sent, "Transfer failed");

        emit PayoutSent(player, amount, address(this).balance);
        emit VaultBalanceChanged(address(this).balance, peakBalance);
    }

    /// @notice Receive bet from game contract
    function receiveBet() external payable onlyGame {
        if (address(this).balance > peakBalance) {
            peakBalance = address(this).balance;
        }
        emit VaultBalanceChanged(address(this).balance, peakBalance);
    }

    // ═══ RISK MANAGEMENT ═══

    /// @notice Adjust max bet percent (only callable by ReactiveRiskGuardian)
    function setMaxBetPercent(uint256 _percent) external onlyRiskGuardian {
        require(_percent >= 10 && _percent <= 500, "Range: 0.1% to 5%");
        uint256 old = maxBetPercent;
        maxBetPercent = _percent;
        emit MaxBetPercentChanged(old, _percent);
    }

    // ═══ VIEWS ═══

    /// @notice Dynamic max bet based on vault balance
    function getMaxBet() external view returns (uint256) {
        return (address(this).balance * maxBetPercent) / 10000;
    }

    /// @notice Hard-capped max payout
    function getMaxPayout() public view returns (uint256) {
        return (address(this).balance * maxPayoutPercent) / 10000;
    }

    /// @notice Vault health as percentage of peak (0-100)
    function getHealthPercent() external view returns (uint256) {
        if (peakBalance == 0) return 100;
        return (address(this).balance * 100) / peakBalance;
    }

    function getBalance() external view returns (uint256) {
        return address(this).balance;
    }

    // ═══ EMERGENCY ═══

    function emergencyWithdraw() external onlyOwner {
        uint256 bal = address(this).balance;
        (bool sent, ) = payable(owner).call{value: bal}("");
        require(sent, "Transfer failed");
        emit EmergencyWithdraw(owner, bal);
    }

    receive() external payable {
        if (address(this).balance > peakBalance) {
            peakBalance = address(this).balance;
        }
        emit VaultFunded(msg.sender, msg.value, address(this).balance);
        emit VaultBalanceChanged(address(this).balance, peakBalance);
    }
}

contracts/ReactiveLeaderboard.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

import {SomniaEventHandler} from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";

/// @title ReactiveLeaderboard - Auto-updating player rankings via Somnia Reactivity
/// @notice Subscribes to GameWon events. Maintains top 10 leaderboard on-chain.
/// @dev Category: Gaming
contract ReactiveLeaderboard is SomniaEventHandler {

    struct PlayerStats {
        uint256 totalWon;
        uint256 biggestWin;
        uint256 biggestMultiplier; // WAD scaled
        uint256 gamesWon;
        uint256 gamesPlayed;
        uint256 lastActive;
    }

    struct LeaderEntry {
        address player;
        uint256 biggestWin;
        uint256 biggestMultiplier;
    }

    uint8 public constant MAX_LEADERS = 10;

    mapping(address => PlayerStats) public playerStats;
    LeaderEntry[10] public leaderboard;
    uint8 public leaderCount;

    uint256 public totalGamesTracked;
    uint256 public totalPayoutsTracked;

    // ═══ EVENTS ═══
    event LeaderboardUpdated(address indexed player, uint256 biggestWin, uint256 multiplier, uint8 rank);
    event PlayerStatsUpdated(address indexed player, uint256 totalWon, uint256 gamesWon);

    /// @notice Reactive handler — called by Somnia validators on GameWon events
    function _onEvent(
        address,
        bytes32[] calldata eventTopics,
        bytes calldata data
    ) internal override {
        bytes32 gameWonSig = keccak256("GameWon(uint256,address,uint256,uint256)");

        if (eventTopics[0] == gameWonSig) {
            // topics[2] = player (indexed)
            address player = address(uint160(uint256(eventTopics[2])));
            // data = (uint256 payout, uint256 multiplier)
            (uint256 payout, uint256 multiplier) = abi.decode(data, (uint256, uint256));

            _processWin(player, payout, multiplier);
        }
    }

    function _processWin(address player, uint256 payout, uint256 multiplier) internal {
        // Update player stats
        PlayerStats storage stats = playerStats[player];
        stats.totalWon += payout;
        stats.gamesWon++;
        stats.lastActive = block.timestamp;

        if (payout > stats.biggestWin) stats.biggestWin = payout;
        if (multiplier > stats.biggestMultiplier) stats.biggestMultiplier = multiplier;

        totalGamesTracked++;
        totalPayoutsTracked += payout;

        emit PlayerStatsUpdated(player, stats.totalWon, stats.gamesWon);

        // Update leaderboard (sorted by biggest win)
        _updateLeaderboard(player, stats.biggestWin, stats.biggestMultiplier);
    }

    function _updateLeaderboard(address player, uint256 biggestWin, uint256 biggestMult) internal {
        // Check if player already on board
        int8 existingIdx = -1;
        for (uint8 i = 0; i < leaderCount; i++) {
            if (leaderboard[i].player == player) {
                existingIdx = int8(i);
                leaderboard[i].biggestWin = biggestWin;
                leaderboard[i].biggestMultiplier = biggestMult;
                break;
            }
        }

        // If not on board and board not full, add
        if (existingIdx == -1 && leaderCount < MAX_LEADERS) {
            leaderboard[leaderCount] = LeaderEntry(player, biggestWin, biggestMult);
            leaderCount++;
        } else if (existingIdx == -1) {
            // Board full — check if player beats the last entry
            if (biggestWin > leaderboard[leaderCount - 1].biggestWin) {
                leaderboard[leaderCount - 1] = LeaderEntry(player, biggestWin, biggestMult);
            }
        }

        // Bubble sort (small array, gas-acceptable)
        for (uint8 i = 0; i < leaderCount; i++) {
            for (uint8 j = i + 1; j < leaderCount; j++) {
                if (leaderboard[j].biggestWin > leaderboard[i].biggestWin) {
                    LeaderEntry memory temp = leaderboard[i];
                    leaderboard[i] = leaderboard[j];
                    leaderboard[j] = temp;
                }
            }
        }

        // Find player's rank and emit
        for (uint8 i = 0; i < leaderCount; i++) {
            if (leaderboard[i].player == player) {
                emit LeaderboardUpdated(player, biggestWin, biggestMult, i + 1);
                break;
            }
        }
    }

    // ═══ VIEWS ═══

    function getLeaderboard() external view returns (LeaderEntry[10] memory) {
        return leaderboard;
    }

    function getPlayerStats(address player) external view returns (PlayerStats memory) {
        return playerStats[player];
    }
}

contracts/ReactiveReferral.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

import {SomniaEventHandler} from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";

/// @title ReactiveReferral - Automatic referral rewards via Somnia Reactivity
/// @notice Subscribes to BetPlaced events. Credits 1% of bet to referrer.
/// @dev Category: Onchain Tracker
contract ReactiveReferral is SomniaEventHandler {

    uint256 public constant REFERRAL_BPS = 100; // 1% = 100 basis points

    struct ReferralStats {
        uint256 totalEarned;
        uint256 totalReferredVolume;
        uint256 referralCount;
        uint256 pendingBalance;
    }

    mapping(address => ReferralStats) public referralStats;
    mapping(address => address) public referrerOf; // player → who referred them

    uint256 public totalReferralsPaid;
    uint256 public totalReferredVolume;

    // ═══ EVENTS ═══
    event ReferralCredited(address indexed referrer, address indexed player, uint256 betAmount, uint256 reward);
    event ReferralClaimed(address indexed referrer, uint256 amount);
    event ReferralRegistered(address indexed player, address indexed referrer);

    /// @notice Reactive handler — called by Somnia validators on BetPlaced events
    function _onEvent(
        address,
        bytes32[] calldata eventTopics,
        bytes calldata data
    ) internal override {
        bytes32 betPlacedSig = keccak256("BetPlaced(uint256,address,uint256,address)");

        if (eventTopics[0] == betPlacedSig) {
            // topics[2] = player (indexed)
            address player = address(uint160(uint256(eventTopics[2])));
            // data = (uint256 amount, address referrer)
            (uint256 amount, address referrer) = abi.decode(data, (uint256, address));

            if (referrer != address(0) && referrer != player) {
                _creditReferral(referrer, player, amount);
            }
        }
    }

    function _creditReferral(address referrer, address player, uint256 betAmount) internal {
        // Register referral relationship if new
        if (referrerOf[player] == address(0)) {
            referrerOf[player] = referrer;
            referralStats[referrer].referralCount++;
            emit ReferralRegistered(player, referrer);
        }

        // Calculate and credit reward
        uint256 reward = (betAmount * REFERRAL_BPS) / 10000;
        referralStats[referrer].totalEarned += reward;
        referralStats[referrer].totalReferredVolume += betAmount;
        referralStats[referrer].pendingBalance += reward;

        totalReferralsPaid += reward;
        totalReferredVolume += betAmount;

        emit ReferralCredited(referrer, player, betAmount, reward);
    }

    /// @notice Claim accumulated referral rewards
    function claimRewards() external {
        uint256 amount = referralStats[msg.sender].pendingBalance;
        require(amount > 0, "Nothing to claim");
        referralStats[msg.sender].pendingBalance = 0;
        // In production, this would transfer from a reward pool
        // For hackathon demo, we track it as credited
        emit ReferralClaimed(msg.sender, amount);
    }

    // ═══ VIEWS ═══

    function getReferralStats(address referrer) external view returns (ReferralStats memory) {
        return referralStats[referrer];
    }

    function getReferrerOf(address player) external view returns (address) {
        return referrerOf[player];
    }
}

contracts/ReactiveRiskGuardian.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

import {SomniaEventHandler} from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";
import "./KaboomVault.sol";

/// @title ReactiveRiskGuardian - Autonomous vault risk management via Somnia Reactivity
/// @notice Subscribes to GameSettled + VaultBalanceChanged. Auto-tightens/loosens bet limits.
/// @dev Categories: DeFi + Automation
contract ReactiveRiskGuardian is SomniaEventHandler {

    KaboomVault public vault;
    address public owner;

    // Thresholds (health percent of peak)
    uint256 public constant EMERGENCY_THRESHOLD = 50;  // <50% → pause high mines
    uint256 public constant CAUTION_THRESHOLD = 70;    // <70% → tighten to 0.5%
    uint256 public constant HEALTHY_THRESHOLD = 90;    // >90% → restore to 1%

    // Risk states
    enum RiskLevel { Healthy, Caution, Emergency }
    RiskLevel public currentRisk;

    // Track stats
    uint256 public totalGamesProcessed;
    uint256 public lastAdjustmentBlock;

    // ═══ EVENTS ═══
    event RiskAdjusted(RiskLevel level, uint256 healthPercent, uint256 newMaxBetPercent);
    event WhaleActivityFlagged(address indexed player, uint256 amount);
    event GuardianTriggered(uint256 gameId, bool won, uint256 healthPercent);

    constructor(address _vault) {
        vault = KaboomVault(payable(_vault));
        owner = msg.sender;
        currentRisk = RiskLevel.Healthy;
    }

    /// @notice Called by Somnia validators when subscribed events fire
    /// @dev Decodes GameSettled or VaultBalanceChanged and adjusts risk
    function _onEvent(
        address,
        bytes32[] calldata eventTopics,
        bytes calldata data
    ) internal override {
        // GameSettled(uint256 gameId, address player, bool won, uint256 amount, uint256 multiplier)
        bytes32 gameSettledSig = keccak256("GameSettled(uint256,address,bool,uint256,uint256)");
        // VaultBalanceChanged(uint256 newBalance, uint256 peakBalance)
        bytes32 vaultChangedSig = keccak256("VaultBalanceChanged(uint256,uint256)");

        bytes32 eventSig = eventTopics[0];

        if (eventSig == gameSettledSig) {
            _handleGameSettled(eventTopics, data);
        } else if (eventSig == vaultChangedSig) {
            _handleVaultChanged(data);
        }
    }

    function _handleGameSettled(bytes32[] calldata topics, bytes calldata data) internal {
        // Decode: gameId from topics[1], player from topics[2]
        // data: (bool won, uint256 amount, uint256 multiplier)
        (bool won, , ) = abi.decode(data, (bool, uint256, uint256));

        totalGamesProcessed++;

        uint256 health = vault.getHealthPercent();
        emit GuardianTriggered(uint256(topics[1]), won, health);

        _adjustRisk(health);
    }

    function _handleVaultChanged(bytes calldata data) internal {
        (uint256 newBalance, uint256 peak) = abi.decode(data, (uint256, uint256));
        uint256 health = peak > 0 ? (newBalance * 100) / peak : 100;
        _adjustRisk(health);
    }

    function _adjustRisk(uint256 healthPercent) internal {
        RiskLevel newLevel;
        uint256 newMaxBet;

        if (healthPercent < EMERGENCY_THRESHOLD) {
            newLevel = RiskLevel.Emergency;
            newMaxBet = 25; // 0.25%
        } else if (healthPercent < CAUTION_THRESHOLD) {
            newLevel = RiskLevel.Caution;
            newMaxBet = 50; // 0.5%
        } else if (healthPercent >= HEALTHY_THRESHOLD) {
            newLevel = RiskLevel.Healthy;
            newMaxBet = 100; // 1%
        } else {
            return; // In between, no change
        }

        if (newLevel != currentRisk) {
            currentRisk = newLevel;
            lastAdjustmentBlock = block.number;
            vault.setMaxBetPercent(newMaxBet);
            emit RiskAdjusted(newLevel, healthPercent, newMaxBet);
        }
    }

    /// @notice Flag whale activity (called by ReactiveWhaleAlert)
    function flagWhaleActivity(address player, uint256 amount) external {
        emit WhaleActivityFlagged(player, amount);
        // Could trigger additional risk tightening here
        uint256 health = vault.getHealthPercent();
        if (health < 80) {
            _adjustRisk(health);
        }
    }
}

contracts/ReactiveWhaleAlert.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.30;

import {SomniaEventHandler} from "@somnia-chain/reactivity-contracts/contracts/SomniaEventHandler.sol";
import "./KaboomVault.sol";
import "./ReactiveRiskGuardian.sol";

/// @title ReactiveWhaleAlert - Monitors large bets via Somnia Reactivity
/// @notice Subscribes to BetPlaced events. Flags bets > 5% of vault and notifies RiskGuardian.
/// @dev Category: Onchain Tracker
contract ReactiveWhaleAlert is SomniaEventHandler {

    uint256 public constant WHALE_THRESHOLD_BPS = 500; // 5% of vault

    KaboomVault public vault;
    ReactiveRiskGuardian public riskGuardian;
    address public owner;

    struct WhaleEvent {
        address player;
        uint256 amount;
        uint256 vaultBalance;
        uint256 percentOfVault; // basis points
        uint256 timestamp;
        uint256 blockNumber;
    }

    WhaleEvent[] public whaleEvents;
    uint256 public totalWhaleAlerts;
    mapping(address => uint256) public whaleAlertCount;

    // ═══ EVENTS ═══
    event WhaleDetected(
        address indexed player,
        uint256 amount,
        uint256 vaultBalance,
        uint256 percentBps,
        uint256 indexed blockNumber
    );
    event RiskGuardianNotified(address indexed player, uint256 amount);

    constructor(address _vault, address _riskGuardian) {
        vault = KaboomVault(payable(_vault));
        riskGuardian = ReactiveRiskGuardian(_riskGuardian);
        owner = msg.sender;
    }

    /// @notice Reactive handler — called by Somnia validators on BetPlaced events
    function _onEvent(
        address,
        bytes32[] calldata eventTopics,
        bytes calldata data
    ) internal override {
        bytes32 betPlacedSig = keccak256("BetPlaced(uint256,address,uint256,address)");

        if (eventTopics[0] == betPlacedSig) {
            // topics[2] = player (indexed)
            address player = address(uint160(uint256(eventTopics[2])));
            // data = (uint256 amount, address referrer)
            (uint256 amount, ) = abi.decode(data, (uint256, address));

            _checkWhale(player, amount);
        }
    }

    function _checkWhale(address player, uint256 amount) internal {
        uint256 vaultBal = vault.getBalance();
        if (vaultBal == 0) return;

        uint256 percentBps = (amount * 10000) / vaultBal;

        if (percentBps >= WHALE_THRESHOLD_BPS) {
            // Whale detected!
            totalWhaleAlerts++;
            whaleAlertCount[player]++;

            WhaleEvent memory evt = WhaleEvent({
                player: player,
                amount: amount,
                vaultBalance: vaultBal,
                percentOfVault: percentBps,
                timestamp: block.timestamp,
                blockNumber: block.number
            });
            whaleEvents.push(evt);

            emit WhaleDetected(player, amount, vaultBal, percentBps, block.number);

            // Notify risk guardian
            riskGuardian.flagWhaleActivity(player, amount);
            emit RiskGuardianNotified(player, amount);
        }
    }

    // ═══ VIEWS ═══

    function getWhaleEventsCount() external view returns (uint256) {
        return whaleEvents.length;
    }

    function getRecentWhaleEvents(uint256 count) external view returns (WhaleEvent[] memory) {
        uint256 total = whaleEvents.length;
        if (count > total) count = total;
        WhaleEvent[] memory recent = new WhaleEvent[](count);
        for (uint256 i = 0; i < count; i++) {
            recent[i] = whaleEvents[total - count + i];
        }
        return recent;
    }
}

